<main class="wrap page"><a class="back" href="/products.php">← Kembali ke katalog</a><?php if ($product): ?><section class="detail-grid"><div class="detail-image-wrap"><div class="detail-image"><?= product_image($product['category']) ?></div><div class="floating-note"><strong>Ready Stock</strong><span>Tersedia untuk pengiriman cepat hari ini</span></div></div><div class="detail-copy"><div class="detail-badges"><span class="tag"><?= htmlspecialchars($product['category']) ?></span><span class="tag soft">Database MySQL</span></div><h1><?= htmlspecialchars($product['name']) ?></h1><p class="price"><?= htmlspecialchars(format_rupiah((float) $product['price'])) ?></p><p><?= htmlspecialchars($product['description']) ?></p><div class="stock-row"><p class="stock">Stok tersedia: <?= (int) $product['stock'] ?></p><span class="pill">Siap dikirim</span></div><div class="hero-actions"><a class="btn primary" href="/cart.php?add=<?= (int) $product['id'] ?>">Tambah ke Keranjang</a><a class="btn ghost" href="/admin.php?edit=<?= (int) $product['id'] ?>">Edit Produk</a></div></div></section><?php else: ?><div class="notice warning"><strong>Produk tidak tersedia.</strong><p><?= htmlspecialchars($database_error ?? 'Item yang dicari tidak ditemukan.') ?></p></div><?php endif; ?></main><?php include __DIR__ . '/footer.php'; ?>
